<?php/******************************************* This file displays the forgot-password  ** form.  It submits to itself, mails a    ** temporary password, and then redirects  ** to login.                               *******************************************/// A file with the database host, user, password, and selected databaserequire_once('../assets/dbconnect.php');if ($_POST['command'] == 'forgot' && strlen($_POST['emailadres'] <= 50)) {  // Handle submission.  This is a one-time only form  // so there will be no problems with handling errors.  $as_email = addslashes($_POST['emailadres']);  $query = "select persoon_id from personalia where emailadres = '$as_email'";  $result = mysql_query($query);  $is_user = mysql_num_rows($result);  if ($is_user == 1) {    // Generate a random password    $alphanum = array('a','b','c','d','e','f','g','h','i','j','k','m','n','o','p','q','r','s','t','u','v','x','y','z','A','B','C','D','E','F','G','H','I','J','K','M','N','P','Q','R','S','T','U','V','W','X','Y','Z','2','3','4','5','6','7','8','9');    $chars = sizeof($alphanum);    $a = time();    mt_srand($a);    for ($i=0; $i < 6; $i++) {      $randnum = intval(mt_rand(0,56));      $password .= $alphanum[$randnum];    }    // One-way encrypt it    $crypt_pass = md5($password);    // Put the temp password in the db    $query = "update personalia set password = '$crypt_pass' where emailadres = '$as_email'";    $result = mysql_query($query) or die('Cannot complete update');     // Send the email    $to      = $_POST['emailadres'];    $from    = "info@helpdisk.nl";    $subject = "Nieuw paswoord";    $msg     = <<< EOMSGJe vroeg om toezending van een nieuw paswoord voor www.HelpDisk.nl/alcohol omdat het oude blijkbaar was zoekgeraakt.Het nieuwe paswoord is:             $passwordJe kunt hiermee inloggen op de URL:             http://www.helpdisk.nl/alcohol/content/login.phpVervolgens kan je jouw instelingen veranderen op:             http://www.helpdisk.nl/alcohol/content/prefs_veranderpass.phpVriendelijk groetend,H.R.J. West			 EOMSG;    $mailsend = mail("$to","$subject","$msg","From: $from\r\nReply-To:info@helpdisk.nl");    // Redirect to login    header("Location: login.php");  } else {    // The email address isn't good, they lose.  }}// -----------------------// Display the form nicely// -----------------------// Superglobal arrays don't work in heredoc$php_self = $_SERVER['PHP_SELF'];$form_str = <<< EOFORMSTR<HTML><HEAD><STYLE TYPE="text/css"><!--BODY, P      {color: black; font-family: verdana; font-size: 10 pt}H1        {color: black; font-family: arial; font-size: 12 pt}--></STYLE></HEAD><BODY><TABLE BORDER=0 CELLPADDING=10 WIDTH=100%><TR><TD BGCOLOR="#F0F8FF" ALIGN=CENTER VALIGN=TOP WIDTH=150></TD><TD BGCOLOR="#FFFFFF" ALIGN=LEFT VALIGN=TOP WIDTH=83%><H1>Aanvraag van een nieuw paswoord</H1><p><b>paswoord vergeten??</b> Geen zorgen...<BR>Als je hieronder jouw emailadres opgeeft dat je hebt gebruikt toen je jezelf hier registreerde dan stuur ik je een nieuw paswoord.<br><i>gebruik dus wel het emailadres dat je eerder gebruikte.</i><br>Als je dat vergeten bent kun je altijd <a href="/registreren.php">opnieuw registeren</a>.</i></p><form action="$php_self" method="post">Email: <input type="text" name="emailadres"><br /><br /><br /><input type="hidden" name="command" value="forgot"><input type="submit" value="verstuur het paswoord"></form></TD></TR></TABLE></BODY></HTML>EOFORMSTR;echo $form_str;?>